1	"use client";
2	
3	import { Cancel01Icon } from "@hugeicons/core-free-icons";
4	import { HugeiconsIcon } from "@hugeicons/react";
5	import { useForm } from "@tanstack/react-form";
6	import { useRouter } from "next/navigation";
7	import type { JSX, ReactNode } from "react";
8	import { useState } from "react";
9	import { Button } from "@/components/ui/button";
10	import {
11	  Field,
12	  FieldDescription,
13	  FieldError,
14	  FieldLabel,
15	} from "@/components/ui/field";
16	import { Input } from "@/components/ui/input";
17	import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
18	import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
19	import { Textarea } from "@/components/ui/textarea";
20	import { useIsHydrated } from "@/hooks/use-is-hydrated";
21	import {
22	  type CourseBasicForm,
23	  CourseBasicFormProvider,
24	} from "@/app/(main)/courses/new/_components/course-basic-form-context";
25	import {
26	  courseBasicFormSchema,
27	  type CourseBasicFormValues,
28	  toCourseBasicSubmissionPayload,
29	} from "@/app/(main)/courses/new/_lib/course-form.schema";
30	import {
31	  createCourse,
32	  type CreateCourseErrorCode,
33	} from "@/app/(main)/courses/new/course-create.action";
34	
35	const errorMessages: Record<CreateCourseErrorCode, string> = {
36	  SUBMIT_FAILED: "コースの作成に失敗しました。時間をおいて再度お試しください。",
37	  CONFLICT:
38	    "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
39	  UNAUTHORIZED: "ログインが必要です。再度ログインしてください。",
40	};
41	
42	const defaultValues: CourseBasicFormValues = {
43	  title: "",
44	  description: "",
45	  slug: "",
46	  tags: [],
47	  visibility: "public",
48	  categorySlug: "",
49	  categoryName: "",
50	};
51	
52	export function CourseCreateForm({
53	  categorySelector,
54	}: {
55	  categorySelector: ReactNode;
56	}): JSX.Element {
57	  const router = useRouter();
58	  const isHydrated = useIsHydrated();
59	  const [submitError, setSubmitError] = useState<string | null>(null);
60	
61	  const form = useForm({
62	    defaultValues,
63	    validators: {
64	      onBlur: courseBasicFormSchema,
65	      onSubmit: courseBasicFormSchema,
66	    },
67	    onSubmit: async ({ value }) => {
68	      setSubmitError(null);
69	      try {
70	        const response = await createCourse(
71	          toCourseBasicSubmissionPayload(value),
72	        );
73	        if (response.success) {
74	          router.push(`/courses/${response.courseId}/sections`);
75	        } else {
76	          setSubmitError(errorMessages[response.code]);
77	        }
78	      } catch {
79	        setSubmitError(errorMessages.SUBMIT_FAILED);
80	      }
81	    },
82	  });
83	
84	  return (
85	    <CourseBasicFormProvider value={form}>
86	      <form
87	        onSubmit={(event) => {
88	          event.preventDefault();
89	          event.stopPropagation();
90	          form.handleSubmit();
91	        }}
92	        className="grid gap-10"
93	        noValidate
94	      >
95	        <section className="grid gap-6">
96	          <header className="grid gap-1">
97	            <h2 className="text-lg font-bold">基本情報</h2>
98	            <p className="text-muted-foreground text-sm">
99	              コース全体のメタ情報を入力します。下書きとして作成され、次の画面でセクション・トピックを入力します。
100	            </p>
101	          </header>
102	
103	          <form.Field name="title">
104	            {(field) => {
105	              // フォーム全体スキーマで onBlur 検証するため、未 blur フィールドにもエラーが伝播する。
106	              // 触っていないフィールドを赤くしないよう isBlurred で表示判定をゲートする。
107	              const showError =
108	                field.state.meta.isBlurred && !field.state.meta.isValid;
109	              return (
110	                <Field data-invalid={showError}>
111	                  <FieldLabel htmlFor={field.name}>
112	                    コースタイトル
113	                    <RequiredOptionalBadge required />
114	                  </FieldLabel>
115	                  <Input
116	                    id={field.name}
117	                    name={field.name}
118	                    aria-invalid={showError}
119	                    value={field.state.value}
120	                    onChange={(event) => field.handleChange(event.target.value)}
121	                    onBlur={field.handleBlur}
122	                    disabled={!isHydrated}
123	                  />
124	                  <FieldDescription>120 文字以内</FieldDescription>
125	                  <FieldError
126	                    errors={showError ? field.state.meta.errors : []}
127	                  />
128	                </Field>
129	              );
130	            }}
131	          </form.Field>
132	
133	          <form.Field name="description">
134	            {(field) => {
135	              const showError =
136	                field.state.meta.isBlurred && !field.state.meta.isValid;
137	              return (
138	                <Field data-invalid={showError}>
139	                  <FieldLabel htmlFor={field.name}>
140	                    コース概要
141	                    <RequiredOptionalBadge required />
142	                  </FieldLabel>
143	                  <Textarea
144	                    id={field.name}
145	                    name={field.name}
146	                    aria-invalid={showError}
147	                    value={field.state.value}
148	                    onChange={(event) => field.handleChange(event.target.value)}
149	                    onBlur={field.handleBlur}
150	                    className="h-32"
151	                    disabled={!isHydrated}
152	                  />
153	                  <FieldDescription>
154	                    対象者・学べる内容など。2000 文字以内
155	                  </FieldDescription>
156	                  <FieldError
157	                    errors={showError ? field.state.meta.errors : []}
158	                  />
159	                </Field>
160	              );
161	            }}
162	          </form.Field>
163	
164	          <form.Field name="slug">
165	            {(field) => {
166	              const showError =
167	                field.state.meta.isBlurred && !field.state.meta.isValid;
168	              return (
169	                <Field data-invalid={showError}>
170	                  <FieldLabel htmlFor={field.name}>
171	                    コース Slug
172	                    <RequiredOptionalBadge required />
173	                  </FieldLabel>
174	                  <Input
175	                    id={field.name}
176	                    name={field.name}
177	                    aria-invalid={showError}
178	                    value={field.state.value}
179	                    onChange={(event) => field.handleChange(event.target.value)}
180	                    onBlur={field.handleBlur}
181	                    disabled={!isHydrated}
182	                    className="md:max-w-md"
183	                  />
184	                  <FieldDescription>
185	                    URL に使われる識別子。半角英数字とハイフンのみ
186	                  </FieldDescription>
187	                  <FieldError
188	                    errors={showError ? field.state.meta.errors : []}
189	                  />
190	                </Field>
191	              );
192	            }}
193	          </form.Field>
194	
195	          {categorySelector}
196	
197	          <form.Field name="visibility">
198	            {(field) => {
199	              const showError =
200	                field.state.meta.isBlurred && !field.state.meta.isValid;
201	              return (
202	                <Field data-invalid={showError}>
203	                  <FieldLabel>
204	                    公開範囲
205	                    <RequiredOptionalBadge required />
206	                  </FieldLabel>
207	                  <RadioGroup
208	                    name={field.name}
209	                    value={field.state.value}
210	                    onValueChange={(value) =>
211	                      field.handleChange(
212	                        value as CourseBasicFormValues["visibility"],
213	                      )
214	                    }
215	                    onBlur={field.handleBlur}
216	                    disabled={!isHydrated}
217	                    aria-invalid={showError}
218	                  >
219	                    {(
220	                      [
221	                        {
222	                          value: "public",
223	                          label: "公開",
224	                          description: "誰でも閲覧可",
225	                        },
226	                        {
227	                          value: "private",
228	                          label: "非公開",
229	                          description: "自分のみ",
230	                        },
231	                      ] as const
232	                    ).map((option) => {
233	                      const id = `${field.name}-${option.value}`;
234	                      return (
235	                        <Field key={option.value} orientation="horizontal">
236	                          <RadioGroupItem id={id} value={option.value} />
237	                          <FieldLabel htmlFor={id} className="font-normal">
238	                            {option.label}
239	                            <span className="text-muted-foreground text-xs">
240	                              （{option.description}）
241	                            </span>
242	                          </FieldLabel>
243	                        </Field>
244	                      );
245	                    })}
246	                  </RadioGroup>
247	                  <FieldError
248	                    errors={showError ? field.state.meta.errors : []}
249	                  />
250	                </Field>
251	              );
252	            }}
253	          </form.Field>
254	
255	          <TagsField form={form} disabled={!isHydrated} />
256	        </section>
257	
258	        {submitError && (
259	          <p role="alert" className="text-destructive text-sm">
260	            {submitError}
261	          </p>
262	        )}
263	
264	        <form.Subscribe
265	          selector={(state) => [state.isSubmitting, state.isValid]}
266	        >
267	          {([isSubmitting, isValid]) => (
268	            <Button
269	              type="submit"
270	              disabled={!isHydrated || isSubmitting || !isValid}
271	              className="justify-self-end"
272	            >
273	              {isSubmitting ? "作成中..." : "コースを作成（下書きとして保存）"}
274	            </Button>
275	          )}
276	        </form.Subscribe>
277	      </form>
278	    </CourseBasicFormProvider>
279	  );
